$sec = ConvertTo-SecureString "usr1cv8" -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential(".\usr1cv8", $sec)
Invoke-Command -ComputerName 26.79.213.133 -Credential $cred -ScriptBlock {
$ErrorActionPreference='Continue'
$log='C:\Users\Public\repair_20260709.log'
function L($m){ $line="[$(Get-Date -Format 'HH:mm:ss')] $m"; Add-Content $log $line; Write-Output $line }

L "=== REPAIR START ==="

# 1. Stop kassa + block updater
Get-Process kassa,moysklad-kassa -EA SilentlyContinue | Stop-Process -Force
Start-Sleep 3
if (Test-Path 'C:\Users\1\AppData\Local\moysklad-kassa-updater') {
  Rename-Item 'C:\Users\1\AppData\Local\moysklad-kassa-updater' 'moysklad-kassa-updater.DISABLED' -Force -EA SilentlyContinue
  L "Updater folder disabled"
}

# 2. Check app integrity
$app='C:\Program Files (x86)\moysklad-kassa\resources\app'
$bad=@()
foreach($f in @('package.json','main.js','index.html','web-retail-opt.js')){
  $fp=Join-Path $app $f
  if (-not (Test-Path $fp)) { $bad+="$f MISSING"; continue }
  $b=[IO.File]::ReadAllBytes($fp)
  if ($b.Length -lt 10) { $bad+="$f EMPTY($($b.Length))" }
  elseif ($f -eq 'package.json' -and $b[0] -ne 123) { $bad+="$f CORRUPT first=$($b[0])" }
}
$nmCount=(Get-ChildItem "$app\node_modules" -EA SilentlyContinue).Count
if ($nmCount -lt 50) { $bad+="node_modules LOW($nmCount)" }
L "Integrity issues: $($bad -join '; ')"

# 3. Find installer source
$src=$null
$candidates=@(
  'C:\Users\Public\kassa342.exe','C:\Users\Public\kassa4307.exe','C:\Users\Public\kassa_full_inst.exe',
  'C:\Users\1\Desktop\esmpack_windows_*.zip'
)
$exe = Get-ChildItem 'C:\Users\Public','C:\Users\1\Desktop','C:\Temp' -Recurse -Include kassa*.exe,moysklad*.exe -EA SilentlyContinue | 
  Where-Object { $_.Length -gt 50MB } | Sort-Object LastWriteTime -Desc | Select-Object -First 3
L "Installers found: $($exe | ForEach-Object { $_.FullName })"

# Extract from temp 7z if exists
foreach($d in Get-ChildItem 'C:\Users\1\AppData\Local\Temp' -Directory -Filter 'ns*' -EA SilentlyContinue | Sort LastWriteTime -Desc){
  $appSrc=Join-Path $d.FullName '7z-out\resources\app'
  if ((Test-Path "$appSrc\package.json") -and (Test-Path "$appSrc\node_modules\winax")) {
    $src=$appSrc; L "Using temp extract: $src"; break
  }
}

# If no temp, extract from newest installer
if (-not $src -and $exe) {
  $inst=$exe[0].FullName
  $extDir='C:\Users\Public\kassa_extract_repair'
  if (-not (Test-Path "$extDir\resources\app\package.json")) {
    New-Item -ItemType Directory -Path $extDir -Force | Out-Null
    L "Extracting $inst ..."
    Start-Process $inst -ArgumentList "/VERYSILENT /SUPPRESSMSGBOXES /DIR=$extDir /EXTRACT" -Wait -NoNewWindow
    Start-Sleep 5
  }
  $appSrc=Join-Path $extDir 'resources\app'
  if (Test-Path "$appSrc\package.json") { $src=$appSrc; L "Using extracted: $src" }
}

# 4. Restore if needed
if ($bad.Count -gt 0 -and $src) {
  L "Restoring app files from $src"
  $dst=$app
  foreach($f in @('package.json','main.js','index.html','web-retail-opt.js','frdriver-jsdeps.js','frdriver-jsdeps.min.js','scala-common-jsdeps.js','scala-common-jsdeps.min.js')){
    if (Test-Path "$src\$f") { Copy-Item "$src\$f" "$dst\$f" -Force }
  }
  if ((Get-ChildItem "$src\node_modules" -EA SilentlyContinue).Count -gt 50) {
    if (Test-Path "$dst\node_modules") { Rename-Item "$dst\node_modules" "node_modules.bak_$(Get-Date -Format HHmmss)" -Force }
    Copy-Item "$src\node_modules" "$dst\node_modules" -Recurse -Force
    L "node_modules restored"
  }
} elseif ($bad.Count -gt 0) {
  L "WARN: files bad but no source found"
}

# Verify after restore
foreach($f in @('package.json','main.js','index.html','web-retail-opt.js')){
  $fp=Join-Path $app $f
  if (Test-Path $fp) { $i=Get-Item $fp; L "$f size=$($i.Length) ok" }
}

# 5. Block updater via hosts (no main.js patch!)
$hosts='C:\Windows\System32\drivers\etc\hosts'
$block='127.0.0.1 electron-updater.moysklad.ru'
if (-not (Select-String -Path $hosts -Pattern 'electron-updater' -Quiet)) {
  Add-Content $hosts "`n$block"
  L "Blocked updater in hosts"
}

# 6. Check shift table
$sql='C:\Users\1\AppData\Local\Temp\sqlite-tools\sqlite3.exe'
$db='C:\Users\1\AppData\Roaming\moysklad-kassa\retail_e87bd531-abc8-11ee-0a80-07a9004c1980.sqlite'
& $sql $db "SELECT id, length(obj), substr(obj,1,200) FROM shift LIMIT 3;" 2>&1 | ForEach-Object { L "SHIFT: $_" }

# 7. Try Remap API with manager@charisma24
$storeId='e87bd531-abc8-11ee-0a80-07a9004c1980'
foreach($pair in @(
  @{l='manager@charisma24';p='Charisma24!'},
  @{l='admin@charisma24';p='Charisma24!'},
  @{l='Varina';p='Charisma24!'}
)){
  $b64=[Convert]::ToBase64String([Text.Encoding]::UTF8.GetBytes("$($pair.l):$($pair.p)"))
  try {
    $r=Invoke-RestMethod "https://api.moysklad.ru/api/remap/1.2/entity/retailstore/$storeId" -Headers @{Authorization="Basic $b64";Accept='application/json;charset=utf-8';'Accept-Encoding'='gzip'} -TimeoutSec 15
    L "API OK user=$($pair.l) name=$($r.name) marking=$($r.markingEnabled) piot=$($r.piotSettings | ConvertTo-Json -Compress)"
    break
  } catch { L "API FAIL $($pair.l): $($_.Exception.Message)" }
}

L "=== REPAIR PHASE 1 DONE ==="
}

