  $p = Start-Process $installer -ArgumentList '/VERYSILENT /SUPPRESSMSGBOXES /NORESTART /CLOSEAPPLICATIONS /FORCECLOSEAPPLICATIONS /LOG=C:\Users\Public\kassa_reinstall.log' -Wait -PassThru -NoNewWindow
  L "Reinstall exit=$($p.ExitCode)"
  Start-Sleep 5
}

# Verify app files
$app='C:\Program Files (x86)\moysklad-kassa\resources\app'
foreach($f in @('package.json','main.js','web-retail-opt.js','index.html')){
  $i=Get-Item "$app\$f" -EA SilentlyContinue
  L "$f size=$($i.Length) mod=$($i.LastWriteTime)"
}

# Check web-retail-opt for corruption
$wro="$app\web-retail-opt.js"
$content = Get-Content $wro -Raw -TotalCount 1 -EA SilentlyContinue
$bad = Select-String -Path $wro -Pattern 'Unexpected|stubbed|DISABLED|var var' | Select -First 3
if ($bad) { L "WRO suspicious: $($bad.Line.Substring(0,100))" } else { L "WRO no obvious patches" }

