$script:msgId=0
function Send-CdpCommand([string]$Method,[hashtable]$Params){
  $script:msgId++
  $id=$script:msgId
  $client = New-Object System.Net.WebSockets.ClientWebSocket
  $ct = New-Object System.Threading.CancellationToken
  $client.ConnectAsync([Uri]$wsUrl,$ct).Wait(20000) | Out-Null
  $payload=@{id=$id;method=$Method;params=$Params}|ConvertTo-Json -Compress -Depth 50
  $bytes=[Text.Encoding]::UTF8.GetBytes($payload)
  $seg=[ArraySegment[byte]]::new($bytes)
  $client.SendAsync($seg,[System.Net.WebSockets.WebSocketMessageType]::Text,$true,$ct).Wait(20000) | Out-Null
  $buf=New-Object byte[] 1048576
  $deadline=(Get-Date).AddSeconds(90)
  while((Get-Date) -lt $deadline){
    $segR=[ArraySegment[byte]]::new($buf)
    $res=$client.ReceiveAsync($segR,$ct).Result
    $text=[Text.Encoding]::UTF8.GetString($buf,0,$res.Count)
    $obj=$text | ConvertFrom-Json
    if($obj.id -eq $id){ $client.CloseAsync([System.Net.WebSockets.WebSocketCloseStatus]::NormalClosure,'done',$ct).Wait(5000)|Out-Null; return $obj }
  }
  throw "Timeout $Method"
}
function Eval-Js([string]$Expression){
  $r=Send-CdpCommand 'Runtime.evaluate' @{expression=$Expression;awaitPromise=$true;returnByValue=$true}
  if($r.result.exceptionDetails){ throw ($r.result.exceptionDetails.text + ' ' + $r.result.exceptionDetails.exception.description) }
  return $r.result.result.value
}
