params.expression:
(() => {
  const el=[...document.querySelectorAll('*')].find(el=>Object.getOwnPropertyNames(el).some(k=>k.startsWith('__reactFiber$')));
  if(!el) return {error:'no react fiber'};
  const key=Object.getOwnPropertyNames(el).find(k=>k.startsWith('__reactFiber$'));
  const seen=new WeakSet();
  const hits=[];
  const walk=(obj,path,depth)=>{
    if(!obj || depth>5 || hits.length>40) return;
    const t=typeof obj;
    if(t==='string') { if(/e87bd531-abc8-11ee-0a80-07a9004c1980|ATOL|РђРўРћР›|30Р|Шоурум/i.test(obj)) hits.push({path,val:obj.slice(0,300)}); return; }
    if(t!=='object' && t!=='function') return;
    if(seen.has(obj)) return; seen.add(obj);
    let keys=[]; try { keys=Object.getOwnPropertyNames(obj).slice(0,80); } catch(e){ return; }
    for(const k of keys){
      let v; try { v=obj[k]; } catch(e){ continue; }
      if(typeof v==='string'){ if(/e87bd531-abc8-11ee-0a80-07a9004c1980|ATOL|РђРўРћР›|30Р|Шоурум/i.test(v)) hits.push({path:path+'.'+k,val:v.slice(0,300)}); }
      else if(v && (typeof v==='object' || typeof v==='function')) walk(v, path+'.'+k, depth+1);
      if(hits.length>40) break;
    }
  };
  walk(el[key], 'fiber', 0);
  return {key,hits};
})()

