param(
    [int]$Port = 9222
)

$ErrorActionPreference = 'Stop'

function Send-Cdp {
    param($Ws, [int]$Id, [string]$Method, $Params)
    $payload = @{ id = $Id; method = $Method; params = $Params } | ConvertTo-Json -Compress -Depth 20
    $bytes = [Text.Encoding]::UTF8.GetBytes($payload)
    $seg = [ArraySegment[byte]]::new($bytes)
    $Ws.SendAsync($seg, [Net.WebSockets.WebSocketMessageType]::Text, $true, [Threading.CancellationToken]::None).Wait()
    $buf = New-Object byte[] 65536
    $res = $Ws.ReceiveAsync([ArraySegment[byte]]::new($buf), [Threading.CancellationToken]::None).Result
    return [Text.Encoding]::UTF8.GetString($buf, 0, $res.Count)
}

$tabs = Invoke-RestMethod "http://127.0.0.1:$Port/json/list"
$tab = $tabs | Where-Object { $_.type -eq 'page' } | Select-Object -First 1
if (-not $tab) { throw 'No CDP page found' }

$ws = [Net.WebSockets.ClientWebSocket]::new()
$ws.ConnectAsync([Uri]$tab.webSocketDebuggerUrl, [Threading.CancellationToken]::None).Wait()

Send-Cdp $ws 1 'Runtime.enable' @{} | Out-Null
Send-Cdp $ws 2 'DOM.enable' @{} | Out-Null

$js = @'
(async () => {
  const sleep = ms => new Promise(r => setTimeout(r, ms));
  const clickByText = (text) => {
    const els = [...document.querySelectorAll('button,div,span,a,[role=button]')];
    const el = els.find(e => (e.innerText || e.textContent || '').trim().includes(text));
    if (!el) return false;
    el.click();
    return true;
  };
  const results = [];
  results.push('shiftBtn=' + clickByText('Открыть смену'));
  await sleep(1500);
  const inputs = [...document.querySelectorAll('input')];
  if (inputs.length) {
    inputs[0].focus();
    inputs[0].value = '0';
    inputs[0].dispatchEvent(new Event('input', { bubbles: true }));
  }
  results.push('ok=' + (clickByText('OK') || clickByText('ОК') || clickByText('Готово')));
  await sleep(3000);
  const bodyText = (document.body && document.body.innerText) ? document.body.innerText.slice(0, 500) : '';
  return results.join(';') + ';body=' + bodyText.replace(/\s+/g, ' ').slice(0, 200);
})()
'@

$resp = Send-Cdp $ws 3 'Runtime.evaluate' @{ expression = $js; awaitPromise = $true; returnByValue = $true }
$ws.Dispose()
Write-Output $resp

