$hostsPath = "$env:Windir\System32\drivers\etc\hosts"
$ip = '192.168.2.103'
$names = @('PORT', 'PORT.portkkm.local', 'port.portkkm.local')

# 1) hosts — short name PORT for 1C Srvr="PORT"
$hosts = Get-Content $hostsPath -Raw -ErrorAction SilentlyContinue
$block = @"
# buhport+1C fix $(Get-Date -Format yyyy-MM-dd)
$ip PORT
$ip PORT.portkkm.local
$ip port.portkkm.local
"@
if ($hosts -notmatch 'buhport\+1C fix') {
    Add-Content -Path $hostsPath -Value "`n$block" -Encoding ASCII
    Write-Host "OK: hosts updated (PORT -> $ip)"
} else {
    Write-Host "OK: hosts already has buhport+1C block"
}

# 2) NRPT — whole AD domain via local DNS
$nrptName = 'PORTKKM-local-DNS'
$existing = Get-DnsClientNrptRule -ErrorAction SilentlyContinue | Where-Object { $_.DisplayName -eq $nrptName }
if (-not $existing) {
    Add-DnsClientNrptRule -Namespace '.portkkm.local' -NameServers $ip -DisplayName $nrptName `
        -Comment '1C UNF: resolve portkkm.local via AD on PORT' | Out-Null
    Write-Host 'OK: NRPT rule for .portkkm.local'
} else {
    Write-Host 'OK: NRPT rule already exists'
}

# 3) Prefer AD DNS on physical LAN adapter (not VPN)
$eth = Get-NetAdapter -ErrorAction SilentlyContinue | Where-Object {
    $_.Status -eq 'Up' -and $_.InterfaceDescription -notmatch 'OpenVPN|TAP|TUN|WireGuard|Wintun|Virtual'
} | Select-Object -First 1
if ($eth) {
    $dns = @('192.168.2.103', '192.168.2.104', '1.0.0.1')
    Set-DnsClientServerAddress -InterfaceIndex $eth.ifIndex -ServerAddresses $dns -ErrorAction SilentlyContinue
    Write-Host "OK: DNS on $($eth.Name) -> $($dns -join ', ')"
}

# 4) Verify
Write-Host "`n=== check ==="
foreach ($n in @('PORT', 'PORT.portkkm.local')) {
    try {
        $r = Resolve-DnsName $n -ErrorAction Stop | Select-Object -First 1
        Write-Host "$n -> $($r.IPAddress)"
    } catch {
        Write-Host "$n -> FAIL ($($_.Exception.Message))"
    }
}
try {
    $p = Test-Connection $ip -Count 1 -Quiet
    Write-Host "ping $ip -> $p"
} catch {
    Write-Host "ping $ip -> FAIL"
}

Write-Host "`nDone. Open 1C / http://PORT"

# Force 192.168.2.x / .10 / .20 via local Ethernet when buhport VPN is on in office.
# OpenVPN Connect (DCO) sometimes ignores pull-filter — this fixes routes after Connect.
# Run as Administrator AFTER OpenVPN shows Connected.

$ErrorActionPreference = 'Continue'

$lan = Get-NetIPAddress -AddressFamily IPv4 -ErrorAction SilentlyContinue |
    Where-Object { $_.IPAddress -match '^192\.168\.2\.' -and $_.PrefixOrigin -ne 'WellKnown' } |
    Select-Object -First 1

if (-not $lan) {
    Write-Host 'SKIP: PC is not on office LAN 192.168.2.x (remote mode — routes stay in VPN).'
    exit 0
}

$eth = Get-NetAdapter -ErrorAction SilentlyContinue | Where-Object { $_.ifIndex -eq $lan.InterfaceIndex }
if (-not $eth) {
    $eth = Get-NetAdapter -ErrorAction SilentlyContinue | Where-Object {
        $_.Status -eq 'Up' -and $_.InterfaceDescription -notmatch 'OpenVPN|TAP|TUN|WireGuard|Wintun|Radmin|Virtual|Hyper-V'
    } | Select-Object -First 1
}

if (-not $eth) {
    Write-Host 'ERROR: office Ethernet adapter not found'
    exit 1
}

Write-Host "Office LAN: $($lan.IPAddress) on $($eth.Name)"

$prefixes = @('192.168.2.0/24', '192.168.10.0/16', '192.168.20.0/16')
foreach ($pfx in $prefixes) {
    Get-NetRoute -AddressFamily IPv4 -DestinationPrefix $pfx -ErrorAction SilentlyContinue |
        Where-Object { $_.InterfaceAlias -match 'OpenVPN|TAP|TUN|WireGuard|Wintun' } |
        ForEach-Object {
            Remove-NetRoute -InputObject $_ -Confirm:$false -ErrorAction SilentlyContinue
            Write-Host "Removed VPN route $pfx via $($_.InterfaceAlias)"
        }

    $onEth = Get-NetRoute -AddressFamily IPv4 -DestinationPrefix $pfx -InterfaceAlias $eth.Name -ErrorAction SilentlyContinue
    if (-not $onEth) {
        New-NetRoute -DestinationPrefix $pfx -InterfaceAlias $eth.Name -NextHop '0.0.0.0' -RouteMetric 1 -PolicyStore ActiveStore -ErrorAction SilentlyContinue | Out-Null
        Write-Host "Added direct route $pfx -> $($eth.Name)"
    } else {
        Set-NetRoute -DestinationPrefix $pfx -InterfaceAlias $eth.Name -RouteMetric 1 -PolicyStore ActiveStore -ErrorAction SilentlyContinue
        Write-Host "OK: $pfx already on $($eth.Name)"
    }
}

Write-Host "`n=== ping check ==="
foreach ($target in @('192.168.2.103', '192.168.2.104')) {
    $ok = Test-Connection $target -Count 1 -Quiet -ErrorAction SilentlyContinue
    Write-Host "ping $target -> $ok"
}

