$hostsPath = "$env:Windir\System32\drivers\etc\hosts"
$mark = 'port-mol-full fix'
$block = @"

# $mark
192.168.2.103  PORT PORT.portkkm.local port.portkkm.local
192.168.2.104  CRM
192.168.2.14   mx.portkkm.ru mail.portkkm.ru
192.168.2.116  miko miko.portkkm.local MIKO
"@

$raw = Get-Content $hostsPath -Raw -ErrorAction SilentlyContinue
if ($raw -notmatch [regex]::Escape($mark)) {
    Add-Content $hostsPath $block -Encoding ASCII
    Write-Host 'OK: hosts'
}

foreach ($pair in @(
    @{Ns='.portkkm.local'; Name='PORTKKM-local'},
    @{Ns='.portkkm.ru'; Name='PORTKKM-ru'}
)) {
    if (-not (Get-DnsClientNrptRule -ErrorAction SilentlyContinue | Where-Object DisplayName -eq $pair.Name)) {
        Add-DnsClientNrptRule -Namespace $pair.Ns -NameServers '192.168.2.103' -DisplayName $pair.Name | Out-Null
        Write-Host "OK: NRPT $($pair.Ns)"
    }
}

Write-Host "`n=== check ==="
@('192.168.2.103','192.168.2.104','192.168.2.14','192.168.2.116') | ForEach-Object {
    Write-Host "ping $_ -> $(Test-Connection $_ -Count 1 -Quiet -EA SilentlyContinue)"
}
try { Write-Host "mx.portkkm.ru -> $((Resolve-DnsName mx.portkkm.ru -EA Stop).IPAddress)" } catch { Write-Host "mx.portkkm.ru -> FAIL" }
